Code.Terraform:
```hcl
resource "aws_codepipeline" "example" {
  name     = "my-pipeline"
  role_arn = aws_iam_role.codepipeline.arn

  stage {
    name = "Deploy"
    action {
      name     = "DeployAction"
      category = "Deploy"
      owner    = "AWS"
      provider = "CloudFormation"
      version  = "1"
      configuration = {
        # CRITICAL: never embed raw credentials; use dynamic references instead
        ParameterOverrides = jsonencode({
          ApiKey = "{{resolve:secretsmanager:my-secret:SecretString:api_key}}"
        })
      }
    }
  }
}
```
